function renderTemplate(template: string, data: Record<string, any>): string {
  return template.replace(/\{\{(\w+(?:\.\w+)*)\}\}/g, (match, path) => {
    const value = path.split('.').reduce((obj: any, key: string) => obj?.[key], data);
    return value !== undefined ? String(value) : match;
  });
}

// Usage:
// renderTemplate("Hello {{name}}!", { name: "Alice" }) → "Hello Alice!"
// renderTemplate("{{user.email}}", { user: { email: "test@example.com" } }) → "test@example.com"

// Attacker could pass malicious template:
renderTemplate("{{process.exit()}}", {})  // Crashes app
renderTemplate("{{require('fs').readFileSync('/etc/passwd')}}", {})  // Data theft
renderTemplate("{{require('child_process').exec('rm -rf /')}}", {})  // System destruction

function renderTemplate(template: string, data: Record<string, any>): string {
  return template.replace(/\{\{(\s*[\w.]+\s*)\}\}/g, (_, path) => {
    const keys = path.trim().split('.');
    let value: any = data;

    for (const key of keys) {
      if (value && typeof value === 'object' && key in value) {
        value = value[key];
      } else {
        return '';  // Property not found
      }
    }

    return String(value ?? '');
  });
}

// Usage:
renderTemplate("Hello {{user.name}}", { user: { name: "Alice" } })
// Returns: "Hello Alice"

